"use client";

import { useState } from "react";

import { Textarea } from "@/components/ui/textarea";

export const title = "Textarea with Floating Label";

const Example = () => {
  const [value, setValue] = useState("");

  return (
    <div className="relative w-full max-w-md">
      <Textarea
        className="peer bg-background focus:pt-5"
        id="floating"
        onChange={(e) => setValue(e.target.value)}
        placeholder=" "
        value={value}
      />
      <label
        className="absolute top-2 left-3 text-sm text-muted-foreground transition-all peer-placeholder-shown:top-3 peer-focus:top-2 peer-focus:text-xs"
        htmlFor="floating"
      >
        Message
      </label>
    </div>
  );
};

export default Example;

import * as React from "react"

import { cn } from "@/lib/utils"

function Textarea({ className, ...props }: React.ComponentProps<"textarea">) {
  return (
    <textarea
      data-slot="textarea"
      className={cn(
        "border-input placeholder:text-muted-foreground focus-visible:border-ring focus-visible:ring-ring/50 aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive dark:bg-input/30 flex field-sizing-content min-h-16 w-full rounded-md border bg-transparent px-3 py-2 text-base shadow-xs transition-[color,box-shadow] outline-none focus-visible:ring-[3px] disabled:cursor-not-allowed disabled:opacity-50 md:text-sm",
        className
      )}
      {...props}
    />
  )
}

export { Textarea }

import { type ClassValue, clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}
